{
  "summary": "Proponemos un plan mínimo y robusto para estabilizar la app, enfocándonos en pruebas E2E, validación de exportes y métricas básicas. Priorizamos la prueba E2E para asegurar el flujo de roles, seguida de la validación automática de archivos descargados y, finalmente, el setup de métricas para monitoreo. Se mantiene el enfoque en correcciones bloqueantes, evitando expansiones. Estrategias simples: usar Playwright para E2E, validar archivos en tests y trackear eventos clave. Total: 78 palabras.",
  "priority_order": ["e2e", "exports", "metrics"],
  "e2e": {
    "critical_assertions": ["Verificar que el rol CEO cambia a modo vista usuario correctamente", "Confirmar navegación al expediente sin errores", "Asegurar regreso al rol CEO con permisos intactos"],
    "test_strategy": "Utilizar Playwright para simular el flujo completo: login como CEO, activar vista usuario, navegar al expediente y regresar, con aserciones en cada paso para validar estados y UI.",
    "main_risks": ["Posibles fallos en autenticación debido a cambios en sesiones", "Alteraciones en la interfaz que invaliden selectores de elementos"]
  },
  "exports": {
    "critical_assertions": ["Confirmar que el archivo CSV o PDF se descarga exitosamente", "Verificar que el contenido del archivo coincida con los datos esperados"],
    "validation_strategy": "En las pruebas con Vitest y Playwright, descargar el blob, guardarlo temporalmente y usar librerías como 'papaparse' para CSV o 'pdfjs' para PDF para validar el contenido automáticamente.",
    "main_risks": ["Inconsistencias en rutas de archivos entre entornos de prueba y producción", "Variaciones en formatos que podrían causar falsos positivos en validaciones"]
  },
  "metrics": {
    "events": ["Acceso a modo vista usuario", "Descarga de exporte CSV/PDF", "Navegación al expediente y regreso"],
    "funnel": ["Inicio sesión como CEO", "Cambio a vista usuario", "Acceso a expediente", "Regreso a CEO"],
    "implementation_hint": "Integrar eventos con una herramienta mínima como un logger personalizado o segmento.io, trackeando solo datos esenciales en el frontend con tRPC para enviar al backend."
  },
  "recommended_sequence": ["Implementar y ejecutar la prueba E2E para validar el flujo", "Añadir la validación automática de exportes en los tests existentes", "Configurar el tracking de métricas y embudo básico"],
  "what_not_to_do": ["No introducir nuevas funcionalidades o flujos no relacionados", "Evitar expandir el scope a pruebas no críticas", "No realizar optimizaciones o cambios en código que no sean correcciones directas"]
}
